$bytes = [System.IO.File]::ReadAllBytes\(""C:\\Users\\user\\Documents\\new\\build\\screenshots\\boot_test2.ppm""\)
# Parse PPM P6 header
$headerEnd = 0
$newlines = 0
for \($i = 0; $i -lt $bytes.Length; $i++\) {
    if \($bytes[$i] -eq 10\) { $newlines++ }
    if \($newlines -eq 3\) { $headerEnd = $i + 1; break }
}
# Get dimensions from header
