        $r = $bytes[$off]; $g = $bytes[$off+1]; $b = $bytes[$off+2]
        Write-Output ""  [$x,$y]: R=$r G=$g B=$b""
    }
}
')

Bash(powershell.exe -Command '
$bytes = [System.IO.File]::ReadAllBytes\(""C:\\Users\\user\\Documents\\new\\build\\screenshots\\boot_test3.ppm""\)
$headerEnd = 0
$newlines = 0
for \($i = 0; $i -lt $bytes.Length; $i++\) {
    if \($bytes[$i] -eq 10\) { $newlines++ }
    if \($newlines -eq 3\) { $headerEnd = $i + 1; break }
}
$header = [System.Text.Encoding]::ASCII.GetString\($bytes, 0, $headerEnd\)
$lines = $header.Split\([char]10\)
Write-Output ""Header: $\($lines[0]\) $\($lines[1]\) $\($lines[2]\)""
$dims = $lines[1].Split\("" ""\)
$w = [int]$dims[0]; $h = [int]$dims[1]
Write-Output ""Size: ${w}x${h}""

# Sample various positions to detect GUI elements
$positions = @\(
    # Top-left corner
    @\(0, 0\), @\(50, 0\), @\(100, 0\),
    # Desktop area
    @\(50, 50\), @\(200, 200\), @\(500, 300\), @\(800, 400\),
    # Window area \(150,100 is where first window starts\)
    @\(150, 100\), @\(200, 110\), @\(350, 150\), @\(350, 300\),
    # Second window \(600, 200\)
    @\(600, 200\), @\(700, 210\), @\(750, 300\),
    # Taskbar area \(bottom\)
    @\(50, 740\), @\(200, 740\), @\(500, 750\), @\(900, 750\),
    # Very bottom
    @\(50, 766\), @\(500, 766\)
\)
foreach \($pos in $positions\) {
    $x = $pos[0]; $y = $pos[1]
    if \($x -ge $w -or $y -ge $h\) { continue }
    $off = $headerEnd + \($y * $w + $x\) * 3
    $r = $bytes[$off]; $g = $bytes[$off+1]; $b = $bytes[$off+2]
    $color = ""unknown""
    if \($r -eq 255 -and $g -eq 255 -and $b -eq 0\) { $color = ""YELLOW"" }
    elseif \($r -eq 0 -and $g -eq 255 -and $b -eq 0\) { $color = ""GREEN"" }
    elseif \($r -eq 0 -and $g -eq 0 -and $b -eq 0\) { $color = ""BLACK"" }
    elseif \($r -eq 255 -and $g -eq 255 -and $b -eq 255\) { $color = ""WHITE"" }
    elseif \($r -eq 0 -and $g -eq 0 -and $b -eq 255\) { $color = ""BLUE"" }
    elseif \($r -eq 255 -and $g -eq 0 -and $b -eq 0\) { $color = ""RED"" }
    elseif \($r -eq 0 -and $g -eq 255 -and $b -eq 255\) { $color = ""CYAN"" }
    elseif \($r -eq 255 -and $g -eq 0 -and $b -eq 255\) { $color = ""MAGENTA"" }
    elseif \($r -eq 51 -and $g -eq 85 -and $b -eq 119\) { $color = ""DESKTOP_BG"" }
    elseif \($r -eq 0 -and $g -eq 85 -and $b -eq 170\) { $color = ""TITLEBAR"" }
    elseif \($r -eq 240 -and $g -eq 240 -and $b -eq 240\) { $color = ""WINDOW_BG"" }
    elseif \($r -eq 26 -and $g -eq 26 -and $b -eq 46\) { $color = ""TASKBAR"" }
    Write-Output ""  [$x,$y]: R=$r G=$g B=$b \($color\)""
}
')

Bash(powershell.exe -Command '
$bytes = [System.IO.File]::ReadAllBytes\(""C:\\Users\\user\\Documents\\new\\build\\screenshots\\final_test.ppm""\)
$headerEnd = 0; $newlines = 0
for \($i = 0; $i -lt $bytes.Length; $i++\) {
    if \($bytes[$i] -eq 10\) { $newlines++ }
    if \($newlines -eq 3\) { $headerEnd = $i + 1; break }
}
$header = [System.Text.Encoding]::ASCII.GetString\($bytes, 0, $headerEnd\)
$lines = $header.Split\([char]10\)
$dims = $lines[1].Split\("" ""\)
$w = [int]$dims[0]; $h = [int]$dims[1]
Write-Output ""Screen: ${w}x${h}""

# Count distinct colors to verify it is not a solid screen
$colorSet = @{}
$step = 50
for \($y = 0; $y -lt $h; $y += $step\) {
    for \($x = 0; $x -lt $w; $x += $step\) {
        $off = $headerEnd + \($y * $w + $x\) * 3
        $key = ""$\($bytes[$off]\),$\($bytes[$off+1]\),$\($bytes[$off+2]\)""
        $colorSet[$key] = $true
    }
}
Write-Output ""Distinct colors sampled: $\($colorSet.Count\)""

# Check for key GUI elements
$checks = @{
    ""Desktop BG"" = @\(800, 50\)
    ""Titlebar 1"" = @\(200, 110\)
    ""Window BG 1"" = @\(300, 250\)
    ""Titlebar 2"" = @\(700, 210\)
    ""Window BG 2"" = @\(750, 300\)
    ""Taskbar"" = @\(500, 750\)
    ""Start Btn"" = @\(30, 740\)
}
foreach \($name in $checks.Keys\) {
    $pos = $checks[$name]
    $off = $headerEnd + \($pos[1] * $w + $pos[0]\) * 3
    Write-Output ""${name}: R=$\($bytes[$off]\) G=$\($bytes[$off+1]\) B=$\($bytes[$off+2]\)""
}
')

