Bash(/tmp/check_usb.ps1 << 'PSEOF'
$f = 'C:\\Users\\user\\Documents\\new\\build\\screen_usb.ppm'
if \(!\(Test-Path $f\)\) { Write-Host "No screenshot"; exit }
$bytes = [IO.File]::ReadAllBytes\($f\)
$nlCount = 0; $hdrLen = 0
for \($i = 0; $i -lt $bytes.Length; $i++\) {
    if \($bytes[$i] -eq 10\) { $nlCount++; if \($nlCount -eq 3\) { $hdrLen = $i + 1; break } }
}
$hdr = [Text.Encoding]::ASCII.GetString\($bytes, 0, $hdrLen\)
Write-Host "Header: $\($hdr.Trim\(\)\)"
$lines = $hdr.Trim\(\).Split\("`n"\)
$dims = $lines[1].Split\(' '\)
$w = [int]$dims[0]; $h = [int]$dims[1]

# Check for desktop bg \(51,85,119\) and non-bg pixels near expected cursor
foreach \($pt in @\(@\(512,384\),@\(612,484\),@\(712,584\),@\(100,100\),@\(800,600\)\)\) {
    $x = $pt[0]; $y = $pt[1]
    if \($x -lt $w -and $y -lt $h\) {
        $off = $hdrLen + \($y * $w + $x\) * 3
        $r = $bytes[$off]; $g = $bytes[$off+1]; $b = $bytes[$off+2]
        $isBg = \($r -eq 51 -and $g -eq 85 -and $b -eq 119\)
        Write-Host "\($x,$y\): R=$r G=$g B=$b $\(if\($isBg\){'[BG]'}else{'[NOT BG]'}\)"
    }
}
PSEOF)

Bash(/tmp/check_cursor.ps1 << 'PSEOF'
$f = 'C:\\Users\\user\\Documents\\new\\build\\screen_usb.ppm'
$bytes = [IO.File]::ReadAllBytes\($f\)
$nlCount = 0; $hdrLen = 0
for \($i = 0; $i -lt $bytes.Length; $i++\) {
    if \($bytes[$i] -eq 10\) { $nlCount++; if \($nlCount -eq 3\) { $hdrLen = $i + 1; break } }
}
$w = 1024; $h = 768

# Scan for white pixels \(cursor is white\) in a grid
$found = @\(\)
for \($y = 0; $y -lt $h; $y += 20\) {
    for \($x = 0; $x -lt $w; $x += 20\) {
        $off = $hdrLen + \($y * $w + $x\) * 3
        $r = $bytes[$off]; $g = $bytes[$off+1]; $b = $bytes[$off+2]
        if \($r -eq 255 -and $g -eq 255 -and $b -eq 255\) {
            $found += "\($x,$y\)"
        }
    }
}
Write-Host "White pixels found at: $\($found -join ', '\)"

# Also check what's near \(512,184\) - expected cursor after Y subtract
foreach \($pt in @\(@\(512,184\),@\(512,584\),@\(712,184\),@\(712,584\)\)\) {
    $x = $pt[0]; $y = $pt[1]
    $off = $hdrLen + \($y * $w + $x\) * 3
    $r = $bytes[$off]; $g = $bytes[$off+1]; $b = $bytes[$off+2]
    Write-Host "\($x,$y\): R=$r G=$g B=$b"
}

# Check taskbar area \(y=738 = SCREEN_HEIGHT - 30\)
$off = $hdrLen + \(738 * $w + 512\) * 3
Write-Host "Taskbar\(512,738\): R=$\($bytes[$off]\) G=$\($bytes[$off+1]\) B=$\($bytes[$off+2]\)"
PSEOF)

Bash(/tmp/check_usb3.ps1 << 'PSEOF'
$f = 'C:\\Users\\user\\Documents\\new\\build\\screen_usb3.ppm'
if \(!\(Test-Path $f\)\) { Write-Host "No screenshot"; exit }
$bytes = [IO.File]::ReadAllBytes\($f\)
$nlCount = 0; $hdrLen = 0
for \($i = 0; $i -lt $bytes.Length; $i++\) {
    if \($bytes[$i] -eq 10\) { $nlCount++; if \($nlCount -eq 3\) { $hdrLen = $i + 1; break } }
}
$lines = \([Text.Encoding]::ASCII.GetString\($bytes, 0, $hdrLen\)\).Trim\(\).Split\("`n"\)
$dims = $lines[1].Split\(' '\)
$w = [int]$dims[0]; $h = [int]$dims[1]
Write-Host "Resolution: ${w}x${h}"

# Scan for white pixels \(cursor\) in the region where cursor should have moved
$found = @\(\)
for \($y = 300; $y -lt 500; $y += 5\) {
    for \($x = 400; $x -lt 900; $x += 5\) {
        if \($x -lt $w -and $y -lt $h\) {
            $off = $hdrLen + \($y * $w + $x\) * 3
            $r = $bytes[$off]; $g = $bytes[$off+1]; $b = $bytes[$off+2]
            if \($r -eq 255 -and $g -eq 255 -and $b -eq 255\) {
                $found += "\($x,$y\)"
            }
        }
    }
}
if \($found.Count -gt 0\) {
    Write-Host "White pixels \(cursor\) found: $\($found[0..4] -join ', '\)"
} else {
    Write-Host "No white cursor pixels found in scan area"
}

# Also scan entire image for any white pixel
$whiteCount = 0
for \($y = 0; $y -lt $h; $y += 10\) {
    for \($x = 0; $x -lt $w; $x += 10\) {
        $off = $hdrLen + \($y * $w + $x\) * 3
        if \($bytes[$off] -eq 255 -and $bytes[$off+1] -eq 255 -and $bytes[$off+2] -eq 255\) {
            $whiteCount++
            if \($whiteCount -le 3\) { Write-Host "White at \($x,$y\)" }
        }
    }
}
Write-Host "Total white pixels found \(sampled\): $whiteCount"
PSEOF)
